#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    long long balance = 0;
    for (int i = 0; i < n; i++) {
        long long x;
        if (scanf("%lld", &x) != 1) return 0;
        balance += x;
    }

    printf("%lld\n", balance);
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char s[1005];
    if (scanf("%1000s", s) != 1) return 0;

    int even = 0, odd = 0;
    for (int i = 0; s[i] != '\0'; i++) {
        if (!isdigit((unsigned char)s[i])) return 0;
        int d = s[i] - '0';
        if (d % 2 == 0) even++;
        else odd++;
    }

    printf("even=%d\nodd=%d\n", even, odd);
    return 0;
}

#include <stdio.h>

int main(void) {
    long long sum = 0;
    int count = 0;
    long long x;

    while (scanf("%lld", &x) == 1) {
        if (x == -1) break;
        sum += x;
        count++;
    }

    printf("sum=%lld\ncount=%d\n", sum, count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1) return 0;

    long long x;
    if (scanf("%lld", &x) != 1) return 0;
    long long mn = x, mx = x;

    for (int i = 1; i < n; i++) {
        if (scanf("%lld", &x) != 1) return 0;
        if (x < mn) mn = x;
        if (x > mx) mx = x;
    }

    printf("min=%lld\nmax=%lld\n", mn, mx);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1) return 0;

    long long sum = 0;
    int pass = 0;
    for (int i = 0; i < n; i++) {
        int score;
        if (scanf("%d", &score) != 1) return 0;
        sum += score;
        if (score >= 50) pass++;
    }

    double avg = (double)sum / n;
    printf("average=%.1f\npass=%d\n", avg, pass);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1) return 0;

    long long total = 0;
    for (int i = 0; i < n; i++) {
        long long p;
        if (scanf("%lld", &p) != 1) return 0;
        if (p >= 100) total += p - p / 10;
        else total += p;
    }

    printf("%lld\n", total);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1) return 0;

    long long base;
    if (scanf("%lld", &base) != 1) return 0;

    long long total = 0;
    for (int i = 1; i < n; i++) {
        long long x;
        if (scanf("%lld", &x) != 1) return 0;
        total += (x - base);
    }

    printf("%lld\n", total);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 2) return 0;

    long long prev, curr;
    if (scanf("%lld", &prev) != 1) return 0;

    int count = 0;
    for (int i = 1; i < n; i++) {
        if (scanf("%lld", &curr) != 1) return 0;
        if (curr == prev) count++;
        prev = curr;
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1) return 0;

    long long pos_sum = 0;
    int neg_count = 0;

    for (int i = 0; i < n; i++) {
        long long x;
        if (scanf("%lld", &x) != 1) return 0;
        if (x > 0) pos_sum += x;
        else if (x < 0) neg_count++;
    }

    printf("positive_sum=%lld\nnegative_count=%d\n", pos_sum, neg_count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1 || n < 1) return 0;

    int last = 1;
    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) return 0;
        last = (last * (x % 10 + 10) % 10) % 10;
    }

    printf("%d\n", last);
    return 0;
}
